import React, { useState, useEffect } from 'react';
import {
  Box, Container, Typography, Card, CardContent, Grid,
  Table, TableBody, TableCell, TableContainer, TableHead, TableRow,
  Paper, Chip, Avatar, IconButton, Tooltip, TextField, InputAdornment,
  Select, MenuItem, FormControl, InputLabel, Button, Dialog, DialogTitle,
  DialogContent, DialogActions, List, ListItem, ListItemText, Divider,
  Alert, CircularProgress, Badge
} from '@mui/material';
import {
  Search, FilterList, Person, Email, TrendingUp, TrendingDown,
  Close, Visibility, AdminPanelSettings, CheckCircle, Cancel, 
  AccountCircle, Settings, Security, ShowChart, LocalAtmRounded,
  CloseOutlined
} from '@mui/icons-material';
import { toast } from 'react-toastify';

const AdminDashboard = () => {
  console.log('AdminDashboard: Componente carregando...');
  
  const [users, setUsers] = useState([]);
  const [filteredUsers, setFilteredUsers] = useState([]);
  const [selectedUser, setSelectedUser] = useState(null);
  const [userDetailsOpen, setUserDetailsOpen] = useState(false);
  const [userTradesOpen, setUserTradesOpen] = useState(false);
  const [loading, setLoading] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const [statusFilter, setStatusFilter] = useState('all');
  const [stats, setStats] = useState({
    totalUsers: 0,
    activeUsers: 0,
    inactiveUsers: 0,
    adminUsers: 0
  });

  useEffect(() => {
    console.log('AdminDashboard: useEffect inicial - carregando usuários...');
    loadUsers();
  }, []);

  useEffect(() => {
    console.log('AdminDashboard: Filtrando usuários...');
    filterUsers();
  }, [users, searchTerm, statusFilter]);

  const loadUsers = async () => {
    try {
      setLoading(true);
      console.log('AdminDashboard: Fazendo requisição para /api/admin/users');
      
      const response = await fetch('/api/admin/users', {
        method: 'GET',
        credentials: 'include',
        headers: {
          'Content-Type': 'application/json',
        },
      });

      if (!response.ok) {
        throw new Error(`HTTP error! status: ${response.status}`);
      }

      const data = await response.json();
      console.log('AdminDashboard: Dados recebidos:', data);
      
      setUsers(data.users || []);
      setStats(data.summary || {
        totalUsers: 0,
        activeUsers: 0,
        inactiveUsers: 0,
        adminUsers: 0
      });
    } catch (error) {
      console.error('Erro ao carregar usuários:', error);
      toast.error('Erro ao carregar lista de usuários');
    } finally {
      setLoading(false);
    }
  };

  const filterUsers = () => {
    let filtered = users;

    // Filtro de busca
    if (searchTerm) {
      filtered = filtered.filter(user =>
        user.full_name.toLowerCase().includes(searchTerm.toLowerCase()) ||
        user.email.toLowerCase().includes(searchTerm.toLowerCase())
      );
    }

    // Filtro de status
    if (statusFilter !== 'all') {
      filtered = filtered.filter(user => {
        if (statusFilter === 'active') return user.is_active;
        if (statusFilter === 'inactive') return !user.is_active;
        if (statusFilter === 'admin') return user.is_admin;
        return true;
      });
    }

    setFilteredUsers(filtered);
  };

  const handleUserClick = async (user) => {
    try {
      setLoading(true);
      const response = await fetch(`/api/admin/user/${user.id}`, {
        method: 'GET',
        credentials: 'include',
        headers: {
          'Content-Type': 'application/json',
        },
      });

      if (!response.ok) {
        throw new Error(`HTTP error! status: ${response.status}`);
      }

      const data = await response.json();
      setSelectedUser(data);
      setUserTradesOpen(true);
    } catch (error) {
      console.error('Erro ao carregar detalhes do usuário:', error);
      toast.error('Erro ao carregar detalhes do usuário');
    } finally {
      setLoading(false);
    }
  };

  const handleCloseTrade = async (tradeId) => {
    if (!selectedUser) return;
    
    try {
      const response = await fetch(`/api/admin/user/${selectedUser.user.id}/trade/${tradeId}/close`, {
        method: 'POST',
        credentials: 'include',
        headers: {
          'Content-Type': 'application/json',
        },
      });

      const data = await response.json();
      
      if (response.ok) {
        toast.success('Trade encerrado com sucesso!');
        // Recarregar dados do usuário
        handleUserClick(selectedUser.user);
        // Recarregar lista de usuários
        loadUsers();
      } else {
        toast.error(data.message || 'Erro ao encerrar trade');
      }
    } catch (error) {
      console.error('Erro ao encerrar trade:', error);
      toast.error('Erro ao encerrar trade');
    }
  };

  const toggleUserStatus = async (userId) => {
    try {
      const response = await fetch(`/api/admin/user/${userId}/toggle-status`, {
        method: 'POST',
        credentials: 'include',
        headers: {
          'Content-Type': 'application/json',
        },
      });

      if (response.ok) {
        toast.success('Status do usuário atualizado');
        loadUsers();
      } else {
        toast.error('Erro ao atualizar status do usuário');
      }
    } catch (error) {
      console.error('Erro ao atualizar status:', error);
      toast.error('Erro ao atualizar status do usuário');
    }
  };

  const getStatusColor = (isActive) => {
    return isActive ? 'success' : 'error';
  };

  const getStatusText = (isActive) => {
    return isActive ? 'Ativo' : 'Inativo';
  };

  const formatCurrency = (value) => {
    return new Intl.NumberFormat('pt-BR', {
      style: 'currency',
      currency: 'USD',
      minimumFractionDigits: 2,
      maximumFractionDigits: 4
    }).format(value || 0);
  };

  const formatDate = (dateString) => {
    if (!dateString) return 'N/A';
    return new Date(dateString).toLocaleString('pt-BR');
  };

  return (
    <Container maxWidth="xl" sx={{ mt: 4, mb: 4 }}>
      <Box sx={{ display: 'flex', alignItems: 'center', mb: 3 }}>
        <AdminPanelSettings sx={{ mr: 2, fontSize: 40, color: '#f0b90b' }} />
        <Typography variant="h4" component="h1" sx={{ color: '#f0b90b', fontWeight: 'bold' }}>
          Painel Administrativo
        </Typography>
      </Box>

      {/* Cards de Estatísticas */}
      <Grid container spacing={3} sx={{ mb: 4 }}>
        <Grid item xs={12} sm={6} md={3}>
          <Card sx={{ bgcolor: '#1e1e1e', border: '1px solid #333' }}>
            <CardContent>
              <Box sx={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between' }}>
                <Box>
                  <Typography color="textSecondary" gutterBottom variant="h6">
                    Total de Usuários
                  </Typography>
                  <Typography variant="h4" sx={{ color: '#f0b90b' }}>
                    {stats.totalUsers}
                  </Typography>
                </Box>
                <Person sx={{ fontSize: 40, color: '#f0b90b' }} />
              </Box>
            </CardContent>
          </Card>
        </Grid>
        
        <Grid item xs={12} sm={6} md={3}>
          <Card sx={{ bgcolor: '#1e1e1e', border: '1px solid #333' }}>
            <CardContent>
              <Box sx={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between' }}>
                <Box>
                  <Typography color="textSecondary" gutterBottom variant="h6">
                    Usuários Ativos
                  </Typography>
                  <Typography variant="h4" sx={{ color: '#4caf50' }}>
                    {stats.activeUsers}
                  </Typography>
                </Box>
                <CheckCircle sx={{ fontSize: 40, color: '#4caf50' }} />
              </Box>
            </CardContent>
          </Card>
        </Grid>
        
        <Grid item xs={12} sm={6} md={3}>
          <Card sx={{ bgcolor: '#1e1e1e', border: '1px solid #333' }}>
            <CardContent>
              <Box sx={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between' }}>
                <Box>
                  <Typography color="textSecondary" gutterBottom variant="h6">
                    Usuários Inativos
                  </Typography>
                  <Typography variant="h4" sx={{ color: '#f44336' }}>
                    {stats.inactiveUsers}
                  </Typography>
                </Box>
                <Cancel sx={{ fontSize: 40, color: '#f44336' }} />
              </Box>
            </CardContent>
          </Card>
        </Grid>
        
        <Grid item xs={12} sm={6} md={3}>
          <Card sx={{ bgcolor: '#1e1e1e', border: '1px solid #333' }}>
            <CardContent>
              <Box sx={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between' }}>
                <Box>
                  <Typography color="textSecondary" gutterBottom variant="h6">
                    Administradores
                  </Typography>
                  <Typography variant="h4" sx={{ color: '#ff9800' }}>
                    {stats.adminUsers}
                  </Typography>
                </Box>
                <Security sx={{ fontSize: 40, color: '#ff9800' }} />
              </Box>
            </CardContent>
          </Card>
        </Grid>
      </Grid>

      {/* Filtros */}
      <Card sx={{ bgcolor: '#1e1e1e', border: '1px solid #333', mb: 3 }}>
        <CardContent>
          <Grid container spacing={2} alignItems="center">
            <Grid item xs={12} md={6}>
              <TextField
                fullWidth
                placeholder="Buscar por nome ou email..."
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
                InputProps={{
                  startAdornment: (
                    <InputAdornment position="start">
                      <Search sx={{ color: '#f0b90b' }} />
                    </InputAdornment>
                  ),
                }}
                sx={{
                  '& .MuiOutlinedInput-root': {
                    '& fieldset': { borderColor: '#333' },
                    '&:hover fieldset': { borderColor: '#f0b90b' },
                    '&.Mui-focused fieldset': { borderColor: '#f0b90b' },
                  },
                }}
              />
            </Grid>
            <Grid item xs={12} md={3}>
              <FormControl fullWidth>
                <InputLabel sx={{ color: '#f0b90b' }}>Status</InputLabel>
                <Select
                  value={statusFilter}
                  onChange={(e) => setStatusFilter(e.target.value)}
                  label="Status"
                  sx={{
                    '& .MuiOutlinedInput-notchedOutline': { borderColor: '#333' },
                    '&:hover .MuiOutlinedInput-notchedOutline': { borderColor: '#f0b90b' },
                    '&.Mui-focused .MuiOutlinedInput-notchedOutline': { borderColor: '#f0b90b' },
                  }}
                >
                  <MenuItem value="all">Todos</MenuItem>
                  <MenuItem value="active">Ativos</MenuItem>
                  <MenuItem value="inactive">Inativos</MenuItem>
                  <MenuItem value="admin">Administradores</MenuItem>
                </Select>
              </FormControl>
            </Grid>
            <Grid item xs={12} md={3}>
              <Button
                fullWidth
                variant="outlined"
                startIcon={<FilterList />}
                onClick={loadUsers}
                sx={{
                  borderColor: '#f0b90b',
                  color: '#f0b90b',
                  '&:hover': { borderColor: '#f0b90b', bgcolor: 'rgba(240, 185, 11, 0.1)' }
                }}
              >
                Atualizar
              </Button>
            </Grid>
          </Grid>
        </CardContent>
      </Card>

      {/* Tabela de Usuários */}
      <Card sx={{ bgcolor: '#1e1e1e', border: '1px solid #333' }}>
        <CardContent>
          <TableContainer>
            <Table>
              <TableHead>
                <TableRow>
                  <TableCell sx={{ color: '#f0b90b', fontWeight: 'bold' }}>Usuário</TableCell>
                  <TableCell sx={{ color: '#f0b90b', fontWeight: 'bold' }}>Email</TableCell>
                  <TableCell sx={{ color: '#f0b90b', fontWeight: 'bold' }}>Status</TableCell>
                  <TableCell sx={{ color: '#f0b90b', fontWeight: 'bold' }}>Operações</TableCell>
                  <TableCell sx={{ color: '#f0b90b', fontWeight: 'bold' }}>PnL Total</TableCell>
                  <TableCell sx={{ color: '#f0b90b', fontWeight: 'bold' }}>Último Trade</TableCell>
                  <TableCell sx={{ color: '#f0b90b', fontWeight: 'bold' }}>Ações</TableCell>
                </TableRow>
              </TableHead>
              <TableBody>
                {loading ? (
                  <TableRow>
                    <TableCell colSpan={7} align="center">
                      <CircularProgress sx={{ color: '#f0b90b' }} />
                    </TableCell>
                  </TableRow>
                ) : filteredUsers.length === 0 ? (
                  <TableRow>
                    <TableCell colSpan={7} align="center">
                      <Typography color="textSecondary">Nenhum usuário encontrado</Typography>
                    </TableCell>
                  </TableRow>
                ) : (
                  filteredUsers.map((user) => (
                    <TableRow key={user.id} hover>
                      <TableCell>
                        <Box sx={{ display: 'flex', alignItems: 'center' }}>
                          <Avatar sx={{ mr: 2, bgcolor: '#f0b90b' }}>
                            {user.full_name.charAt(0).toUpperCase()}
                          </Avatar>
                          <Box>
                            <Button
                              variant="text"
                              onClick={() => handleUserClick(user)}
                              sx={{
                                color: '#f0b90b',
                                textTransform: 'none',
                                fontWeight: 'bold',
                                '&:hover': { bgcolor: 'rgba(240, 185, 11, 0.1)' }
                              }}
                            >
                              {user.full_name}
                            </Button>
                            {user.is_admin && (
                              <Chip
                                label="Admin"
                                size="small"
                                sx={{ 
                                  ml: 1,
                                  bgcolor: '#ff9800',
                                  color: 'white',
                                  fontSize: '0.75rem'
                                }}
                              />
                            )}
                          </Box>
                        </Box>
                      </TableCell>
                      <TableCell>
                        <Typography variant="body2" sx={{ color: '#f0b90b' }}>
                          {user.email}
                        </Typography>
                      </TableCell>
                      <TableCell>
                        <Chip
                          label={getStatusText(user.is_active)}
                          color={getStatusColor(user.is_active)}
                          size="small"
                        />
                      </TableCell>
                      <TableCell>
                        <Box sx={{ display: 'flex', alignItems: 'center', gap: 1 }}>
                          {user.stats.open_trades > 0 ? (
                            <Badge badgeContent={user.stats.open_trades} color="primary">
                              <ShowChart sx={{ color: '#4caf50' }} />
                            </Badge>
                          ) : (
                            <Typography variant="body2" color="textSecondary">
                              Sem operações
                            </Typography>
                          )}
                          <Typography variant="caption" color="textSecondary">
                            ({user.stats.total_trades} total)
                          </Typography>
                        </Box>
                      </TableCell>
                      <TableCell>
                        <Typography
                          variant="body2"
                          sx={{
                            color: user.stats.total_pnl >= 0 ? '#4caf50' : '#f44336',
                            fontWeight: 'bold'
                          }}
                        >
                          {formatCurrency(user.stats.total_pnl)}
                        </Typography>
                      </TableCell>
                      <TableCell>
                        <Typography variant="body2" color="textSecondary">
                          {user.stats.last_trade_date}
                        </Typography>
                      </TableCell>
                      <TableCell>
                        <Box sx={{ display: 'flex', gap: 1 }}>
                          <Tooltip title="Ver detalhes">
                            <IconButton
                              size="small"
                              onClick={() => handleUserClick(user)}
                              sx={{ color: '#f0b90b' }}
                            >
                              <Visibility />
                            </IconButton>
                          </Tooltip>
                          {!user.is_admin && (
                            <Tooltip title={user.is_active ? 'Desativar' : 'Ativar'}>
                              <IconButton
                                size="small"
                                onClick={() => toggleUserStatus(user.id)}
                                sx={{ color: user.is_active ? '#f44336' : '#4caf50' }}
                              >
                                {user.is_active ? <Cancel /> : <CheckCircle />}
                              </IconButton>
                            </Tooltip>
                          )}
                        </Box>
                      </TableCell>
                    </TableRow>
                  ))
                )}
              </TableBody>
            </Table>
          </TableContainer>
        </CardContent>
      </Card>

      {/* Modal de Dashboard do Usuário */}
      <Dialog
        open={userTradesOpen}
        onClose={() => setUserTradesOpen(false)}
        maxWidth="lg"
        fullWidth
      >
        <DialogTitle sx={{ bgcolor: '#1e1e1e', color: '#f0b90b' }}>
          <Box sx={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between' }}>
            <Typography variant="h5">
              Dashboard - {selectedUser?.user?.full_name}
            </Typography>
            <IconButton onClick={() => setUserTradesOpen(false)} sx={{ color: '#f0b90b' }}>
              <Close />
            </IconButton>
          </Box>
        </DialogTitle>
        <DialogContent sx={{ bgcolor: '#1e1e1e', color: 'white' }}>
          {selectedUser && (
            <Box>
              {/* Informações do Usuário */}
              <Grid container spacing={2} sx={{ mb: 3 }}>
                <Grid item xs={12} md={6}>
                  <Typography variant="h6" sx={{ color: '#f0b90b', mb: 1 }}>
                    Informações do Usuário
                  </Typography>
                  <Typography><strong>Email:</strong> {selectedUser.user.email}</Typography>
                  <Typography><strong>ID Nautilus:</strong> {selectedUser.user.nautilus_user_id || 'N/A'}</Typography>
                  <Typography><strong>Saldo Operacional:</strong> {formatCurrency(selectedUser.user.operational_balance_usd)}</Typography>
                </Grid>
                <Grid item xs={12} md={6}>
                  <Typography variant="h6" sx={{ color: '#f0b90b', mb: 1 }}>
                    Estatísticas
                  </Typography>
                  <Typography><strong>Total de Trades:</strong> {selectedUser.stats.total_trades}</Typography>
                  <Typography><strong>Trades Abertos:</strong> {selectedUser.stats.open_trades}</Typography>
                  <Typography><strong>Taxa de Ganho:</strong> {selectedUser.stats.win_rate}%</Typography>
                  <Typography>
                    <strong>PnL Total:</strong> 
                    <span style={{ color: selectedUser.stats.total_pnl >= 0 ? '#4caf50' : '#f44336', marginLeft: '8px' }}>
                      {formatCurrency(selectedUser.stats.total_pnl)}
                    </span>
                  </Typography>
                </Grid>
              </Grid>

              <Divider sx={{ bgcolor: '#333', mb: 3 }} />

              {/* Lista de Trades */}
              <Typography variant="h6" sx={{ color: '#f0b90b', mb: 2 }}>
                Operações ({selectedUser.trades.length})
              </Typography>
              
              {selectedUser.trades.length === 0 ? (
                <Alert severity="info" sx={{ bgcolor: '#1e1e1e', color: 'white' }}>
                  Nenhuma operação encontrada para este usuário.
                </Alert>
              ) : (
                <TableContainer component={Paper} sx={{ bgcolor: '#1e1e1e', maxHeight: 400 }}>
                  <Table stickyHeader>
                    <TableHead>
                      <TableRow>
                        <TableCell sx={{ bgcolor: '#333', color: '#f0b90b' }}>Símbolo</TableCell>
                        <TableCell sx={{ bgcolor: '#333', color: '#f0b90b' }}>Lado</TableCell>
                        <TableCell sx={{ bgcolor: '#333', color: '#f0b90b' }}>Tamanho</TableCell>
                        <TableCell sx={{ bgcolor: '#333', color: '#f0b90b' }}>Preço Entrada</TableCell>
                        <TableCell sx={{ bgcolor: '#333', color: '#f0b90b' }}>Preço Saída</TableCell>
                        <TableCell sx={{ bgcolor: '#333', color: '#f0b90b' }}>PnL</TableCell>
                        <TableCell sx={{ bgcolor: '#333', color: '#f0b90b' }}>Status</TableCell>
                        <TableCell sx={{ bgcolor: '#333', color: '#f0b90b' }}>Ações</TableCell>
                      </TableRow>
                    </TableHead>
                    <TableBody>
                      {selectedUser.trades.map((trade) => (
                        <TableRow key={trade.id}>
                          <TableCell sx={{ color: 'white' }}>{trade.symbol}</TableCell>
                          <TableCell>
                            <Chip
                              label={trade.side.toUpperCase()}
                              size="small"
                              sx={{
                                bgcolor: trade.side.toLowerCase() === 'long' ? '#4caf50' : '#f44336',
                                color: 'white'
                              }}
                            />
                          </TableCell>
                          <TableCell sx={{ color: 'white' }}>{trade.size}</TableCell>
                          <TableCell sx={{ color: 'white' }}>{formatCurrency(trade.entry_price)}</TableCell>
                          <TableCell sx={{ color: 'white' }}>
                            {trade.exit_price ? formatCurrency(trade.exit_price) : '-'}
                          </TableCell>
                          <TableCell>
                            <Typography
                              sx={{
                                color: trade.pnl >= 0 ? '#4caf50' : '#f44336',
                                fontWeight: 'bold'
                              }}
                            >
                              {formatCurrency(trade.pnl)}
                            </Typography>
                          </TableCell>
                          <TableCell>
                            <Chip
                              label={trade.status.toUpperCase()}
                              size="small"
                              color={trade.status === 'open' ? 'primary' : 'default'}
                            />
                          </TableCell>
                          <TableCell>
                            {trade.status === 'open' && (
                              <Tooltip title="Encerrar Trade">
                                <IconButton
                                  size="small"
                                  onClick={() => handleCloseTrade(trade.id)}
                                  sx={{ color: '#f44336' }}
                                >
                                  <CloseOutlined />
                                </IconButton>
                              </Tooltip>
                            )}
                          </TableCell>
                        </TableRow>
                      ))}
                    </TableBody>
                  </Table>
                </TableContainer>
              )}
            </Box>
          )}
        </DialogContent>
        <DialogActions sx={{ bgcolor: '#1e1e1e' }}>
          <Button onClick={() => setUserTradesOpen(false)} sx={{ color: '#f0b90b' }}>
            Fechar
          </Button>
        </DialogActions>
      </Dialog>
    </Container>
  );
};

export default AdminDashboard;
